import { Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { map } from 'rxjs/operators';
import { Order } from '../../core/models';

@Component({
  selector: 'app-order-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './order-detail.component.html',
  styleUrls: ['./order-detail.component.css'],
})
export class OrderDetailComponent {
  private route = inject(ActivatedRoute);
  loading = signal(false);
  error = signal<string | null>(null);

  // Backend-provided data — kept as a signal per the mockup data contract.
  orders = signal<Order[]>([
    {
      id: 'o-1001', userId: 'demo-admin', status: 'placed', shipName: 'Demo Admin',
      shipAddress: '482 Industrial Pkwy, Salt Lake City, UT 84104', totalCents: 4597,
      createdAt: '2026-07-10T15:24:00Z',
      items: [
        { id: 'oi-1', productId: 'p-1', qty: 2, unitPriceCents: 1899, name: 'Class J Time-Delay Fuse 30A' },
        { id: 'oi-2', productId: 'p-3', qty: 1, unitPriceCents: 749, name: 'DIN-Rail Fuse Holder 1P' },
      ],
    },
    {
      id: 'o-1000', userId: 'demo-admin', status: 'shipped', shipName: 'Demo Admin',
      shipAddress: '482 Industrial Pkwy, Salt Lake City, UT 84104', totalCents: 42900,
      createdAt: '2026-07-02T09:10:00Z',
      items: [
        { id: 'oi-3', productId: 'p-4', qty: 1, unitPriceCents: 42900, name: 'VFD 3HP 480V Drive' },
      ],
    },
  ]);

  private id = toSignal(this.route.paramMap.pipe(map((p) => p.get('id') ?? '')), { initialValue: '' });
  order = computed<Order | undefined>(() => this.orders().find((o) => o.id === this.id()));
}
